class Solution:
    def longestPalindrome(self, word1, word2):
        s = word1 + word2
        n = len(s)
        lps = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n - 1, -1, -1):
            lps[i][i] = 1
            for j in range(i + 1, n):
                if s[i] == s[j]:
                    lps[i][j] = lps[i + 1][j - 1] + 2
                else:
                    lps[i][j] = max(lps[i + 1][j], lps[i][j - 1])
        m1 = len(word1)
        best = 0
        for i in range(m1):
            for j in range(m1, n):
                if s[i] == s[j]:
                    inner = lps[i + 1][j - 1] if i + 1 <= j - 1 else 0
                    best = max(best, 2 + inner)
        return best

