class Solution:
    def longestPalindrome(self, word1, word2):
        s = word1 + word2
        m1 = len(word1)
        n = len(s)
        dp = [[0] * n for _ in range(n)]
        best = 0
        for i in range(n - 1, -1, -1):
            dp[i][i] = 1
            for j in range(i + 1, n):
                if s[i] == s[j]:
                    dp[i][j] = dp[i + 1][j - 1] + 2
                    if i < m1 and j >= m1:
                        best = max(best, dp[i][j])
                else:
                    dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])
        return best

