var longestPalindrome = function(word1, word2) {
    const s = word1 + word2;
    const m1 = word1.length;
    const n = s.length;
    const dp = Array.from({length: n}, () => new Array(n).fill(0));
    let best = 0;
    for (let i = n - 1; i >= 0; i--) {
        dp[i][i] = 1;
        for (let j = i + 1; j < n; j++) {
            if (s[i] === s[j]) {
                dp[i][j] = dp[i + 1][j - 1] + 2;
                if (i < m1 && j >= m1) best = Math.max(best, dp[i][j]);
            } else {
                dp[i][j] = Math.max(dp[i + 1][j], dp[i][j - 1]);
            }
        }
    }
    return best;
};
